                            <SelectBtn label="≥ 7mm (1pt)" active={scores.n===1} onClick={()=>setScores({...scores, n:1})}/>
                            <SelectBtn label="4 - 7mm (2pts)" active={scores.n===2} onClick={()=>setScores({...scores, n:2})}/>
